mapper.sql:
SELECT '0' AS CHK , IVLC.CTKEY /* 센터코드 */ , CT.CTNM /* 센터명 */ , IVLC.OWKEY /* 화주코드 */ , OW.OWNM /* 화주명 */ , IVLC.ICKEY /* 상품코드 */ , IC.ICNM /* 상품명 */ , ICBC.BARCODE /* 상품바코드 */ , IVLC.IVATKEY /* 재고속성코드 */ , IV.PRDCTDATE /* 생산일시 */ , IV.EXPDATE /* 유통기한일시 */ , LC.ZNKEY /* 존코드 */ , ZN.ZNNM /* 존명 */ , LC.ARKEY /* 구역코드 */ , AR.ARNM /* 구역명 */ , IVLC.LCKEY /* 로케이션코드 */ , IVLC.IVSERIALNO /* 용기번호 */ , LC.LCSTORGTYPECD /* 로케이션 보관 유형 코드 */ , IVLC.TOTQTY /* 총 수량 */ , IVLC.AVQTY /* 가용수량 */ , IVLC.ALQTY /* 할당수량 */ , IVLC.HOLDQTY /* 보류수량 */ , IVLC.IVSTATUSCD /* 재고상태코드 */ , IVLC.IVSTATUSCD AS ORGIVSTATUSCD /* 재고상태코드 */ , IVLC.HOLDRSNCD /* 보류사유코드 */ , IVLC.HOLDDTCONT /* 보류상세내용 */ , IVLC.INSERTDATE /* 입력일시 */ , IVLC.INSERTURKEY /* 입력자 */ , IVLC.UPDATEDATE /* 수정일시 */ , IVLC.UPDATEURKEY /* 수정자 */ FROM TWORK_INFO_IVATXLC IVLC INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = IVLC.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = IVLC.OWKEY INNER JOIN TWORK_MST_IC IC ON IC.CTKEY = IVLC.CTKEY AND IC.OWKEY = IVLC.OWKEY AND IC.ICKEY = IVLC.ICKEY LEFT JOIN TWORK_MST_ICBARCODE ICBC ON ICBC.CTKEY = IC.CTKEY AND ICBC.OWKEY = IC.OWKEY AND ICBC.ICKEY = IC.ICKEY AND ICBC.UOM = IC.UOM AND ICBC.USEYN = 'Y' INNER JOIN TWORK_INFO_IVAT IV ON IV.CTKEY = IVLC.CTKEY AND IV.OWKEY = IVLC.OWKEY AND IV.ICKEY = IVLC.ICKEY AND IV.IVATKEY = IVLC.IVATKEY INNER JOIN TWORK_MST_LC LC ON LC.CTKEY = IVLC.CTKEY AND LC.LCKEY = IVLC.LCKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = LC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY
AND IVLC.OWKEY = COALESCE(#{owkey}, #{sowkey}) AND IVLC.TOTQTY > 0
AND #{SEARCH_CONDITION}
#{item}

mapper.select:
/* wms-inventory-invnhold-sql-oracle.xml - selectInvnHoldLExcelList */ WITH T_CODE AS ( SELECT B.CTKEY , B.CTCDHDKEY , B.CTCDDTKEY , B.CTCDDTNM FROM TWORK_MST_CTCD_HD A INNER JOIN TWORK_MST_CTCD_DT B ON B.CTKEY = A.CTKEY AND B.CTCDHDKEY = A.CTCDHDKEY
AND A.DELYN = 'N' AND B.DELYN = 'N'
AND B.LAKEY = #{lakey}
AND A.CTCDHDKEY IN ('IVSTATUSCD', 'HOLDRSNCD')
) SELECT IVLC.CTKEY /* 센터코드 */ , CT.CTNM /* 센터명 */ , IVLC.OWKEY /* 화주코드 */ , OW.OWNM /* 화주명 */ , IVLC.ICKEY /* 상품코드 */ , IC.ICNM /* 상품명 */ , ICBC.BARCODE /* 상품바코드 */ , IVLC.IVATKEY /* 재고속성코드 */ , IV.PRDCTDATE /* 생산일시 */ , IV.EXPDATE /* 유통기한일시 */ , LC.ZNKEY /* 존코드 */ , ZN.ZNNM /* 존명 */ , LC.ARKEY /* 구역코드 */ , AR.ARNM /* 구역명 */ , IVLC.LCKEY /* 로케이션코드 */ , IVLC.IVSERIALNO /* 용기번호 */ , LC.LCSTORGTYPECD /* 로케이션 보관 유형 코드 */ , IVLC.TOTQTY /* 총 수량 */ , IVLC.AVQTY /* 가용수량 */ , IVLC.ALQTY /* 할당수량 */ , IVLC.HOLDQTY /* 보류수량 */ , CD1.CTCDDTNM AS IVSTATUSCD /* 재고상태코드 */ , CD2.CTCDDTNM AS HOLDRSNCD /* 보류사유코드 */ , IVLC.HOLDDTCONT /* 보류상세내용 */ , IVLC.INSERTDATE /* 입력일시 */ , IVLC.INSERTURKEY /* 입력자 */ , IVLC.UPDATEDATE /* 수정일시 */ , IVLC.UPDATEURKEY /* 수정자 */ FROM TWORK_INFO_IVATXLC IVLC INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = IVLC.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = IVLC.OWKEY INNER JOIN TWORK_MST_IC IC ON IC.CTKEY = IVLC.CTKEY AND IC.OWKEY = IVLC.OWKEY AND IC.ICKEY = IVLC.ICKEY LEFT JOIN TWORK_MST_ICBARCODE ICBC ON ICBC.CTKEY = IC.CTKEY AND ICBC.OWKEY = IC.OWKEY AND ICBC.ICKEY = IC.ICKEY AND ICBC.UOM = IC.UOM AND ICBC.USEYN = 'Y' INNER JOIN TWORK_INFO_IVAT IV ON IV.CTKEY = IVLC.CTKEY AND IV.OWKEY = IVLC.OWKEY AND IV.ICKEY = IVLC.ICKEY AND IV.IVATKEY = IVLC.IVATKEY INNER JOIN TWORK_MST_LC LC ON LC.CTKEY = IVLC.CTKEY AND LC.LCKEY = IVLC.LCKEY INNER JOIN TWORK_MST_ZN ZN ON ZN.CTKEY = LC.CTKEY AND ZN.ZNKEY = LC.ZNKEY INNER JOIN TWORK_MST_AR AR ON AR.CTKEY = LC.CTKEY AND AR.ZNKEY = LC.ZNKEY AND AR.ARKEY = LC.ARKEY LEFT JOIN T_CODE CD1 ON CD1.CTKEY = IC.CTKEY AND CD1.CTCDHDKEY = 'IVSTATUSCD' AND CD1.CTCDDTKEY = IVLC.IVSTATUSCD LEFT JOIN T_CODE CD2 ON CD2.CTKEY = IC.CTKEY AND CD2.CTCDHDKEY = 'HOLDRSNCD' AND CD2.CTCDDTKEY = IVLC.HOLDRSNCD
AND IVLC.OWKEY = COALESCE(#{owkey}, #{sowkey}) AND IVLC.TOTQTY > 0
AND #{SEARCH_CONDITION}
#{item}
ORDER BY IVLC.CTKEY , IVLC.OWKEY , IVLC.LCKEY , IVLC.ICKEY , IVLC.IVATKEY

