/* wms-inventory-invnhold-sql-oracle.xml - updateLocation */
UPDATE TWORK_MST_LC
   SET UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
	 , LCHOLDTYPECD = #{lcholdtypecd}
WHERE CTKEY = #{ctkey}
  AND LCKEY = #{lckey}

