/* wms-inventory-invnhold-sql-oracle.xml - selectTWorkInfoIvatxlcxulc - 재고 조회  SQL */
	SELECT CTKEY
		 , OWKEY
		 , LCKEY
		 , ICKEY
		 , ULCKEY
		 , IVATKEY
		 , IVATSTATUS 
		 , COALESCE(TTQTY, 0) AS TTQTY
		 , COALESCE(AVQTY, 0) AS AVQTY
		 , COALESCE(ALQTY, 0) AS ALQTY
		 , COALESCE(PIQTY, 0) AS PIQTY
		 , COALESCE(PAQTY, 0) AS PAQTY
		 , COALESCE(HOQTY, 0) AS HOQTY
		 , COALESCE(LOQTY, 0) AS LOQTY
		 , LOGGRPCD
	  FROM TWORK_INFO_IVATXLCXULC
	 WHERE CTKEY = #{ctkey}
	   AND IVATKEY = #{ivatkey}
	   AND LCKEY   = #{lckey}
	   AND ULCKEY  = #{ulckey}
	   AND OWKEY   = #{owkey}
	   AND ICKEY   = #{ickey}

    	SELECT A.IVATSTATUS 
    	FROM TWORK_INFO_IVATXLCXULC A
    	WHERE   A.CTKEY  = #{ctkey}
            AND A.ULCKEY = #{barcode}
            AND A.LCKEY = #{lckey}
            AND A.IVATKEY = #{ivatkey}
            AND A.OWKEY = #{powner}
            AND A.ICKEY = #{ickey}
		    AND A.TTQTY > 0

mapper.update:

		UPDATE  TWORK_INFO_IVATXLCXULC A  SET 
			IVATSTATUS = '60'	
		WHERE 
		        A.CTKEY  = #{ctkey}
            AND A.ULCKEY = #{barcode}
            AND A.LCKEY = #{lckey}
            AND A.IVATKEY = #{ivatkey}
            AND A.OWKEY = #{powner}
            AND A.ICKEY = #{ickey}
		    AND TTQTY > 0

mapper.select:
/* wms-inventory-invnhold-sql-oracle.xml - selectIvatHoldReq - 재고 요청 정보 조회  SQL */
   SELECT CTKEY, IVATKEY, LCKEY, ULCKEY, OWKEY, ICKEY
		, REQDATE, IVAT_HOLD_TYPE, WKSTATUS, INCHANNELCD, CHG_IVATSTATUS
		, IF_STATUS, IF_STATUS_MSG, REASONTYPE, COMMENTS
	 FROM TWORK_INFO_IVAT_HOLD_REQ 
	WHERE CTKEY = #{ctkey}
	    AND IVATKEY = #{ivatkey}
	    AND LCKEY = #{lckey}
	    AND ULCKEY = #{ulckey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}

mapper.insert:
/* wms-inventory-invnhold-sql-oracle.xml - insertTWorkIvatHoldReq - 재고 요청 정보 등록  SQL */
	INSERT INTO TWORK_INFO_IVAT_HOLD_REQ 
		   (
		     CTKEY
		   , IVATKEY
		   , LCKEY
		   , ULCKEY
		   , OWKEY
		   , ICKEY
		   , REQDATE
		   , IVAT_HOLD_TYPE
		   , WKSTATUS
		   , INCHANNELCD
		   , CHG_IVATSTATUS
		   , REASONTYPE
		   , COMMENTS
		   , IF_STATUS
		   , IF_STATUS_MSG
		   , INSERTDATE 
		   , INSERTURKEY
		   , UPDATEDATE 
		   , UPDATEURKEY
		   ) VALUES (
		     #{ctkey}
		   , #{ivatkey}
		   , #{lckey}
		   , #{ulckey}
		   , #{owkey}
		   , #{ickey}
		   , #{sysdate}
		   , #{ivatHoldType}
		   , #{wkstatus}
		   , #{inchannelcd}
		   , #{ivatstatus}
		   , #{reasontype}
		   , #{comments}
		   , #{processStatus}
		   , #{message}
		   , #{sysdate}
		   , #{surkey}
		   , #{sysdate}
		   , #{surkey}
		   )

mapper.update:
/* wms-inventory-invnhold-sql-oracle.xml - updateTWorkIvatHoldReq - 재고 요청 정보 상태 수정  SQL */
		UPDATE TWORK_INFO_IVAT_HOLD_REQ
		   SET IF_STATUS = #{processStatus}
		   	 , IF_STATUS_MSG = #{message}
		   	 , WKSTATUS = #{wkstatus}

		     , CHG_IVATSTATUS = #{ivatstatus}
		     , IVAT_HOLD_TYPE = #{ivatHoldType}
		   	 , REASONTYPE = #{reasontype}
		     , COMMENTS = #{comments}

		     , UPDATEDATE = #{sysdate}
		     , UPDATEURKEY = #{surkey}
		 WHERE CTKEY = #{ctkey}
		   AND IVATKEY = #{ivatkey}
		   AND LCKEY = #{lckey}
		   AND ULCKEY = #{ulckey}
		   AND OWKEY = #{owkey}
		   AND ICKEY = #{ickey}
